python3 -c "
import base64, os, json, urllib.request

# Read image and encode to base64
with open('/tmp_workspace/poster_original.png', 'rb') as f:
    img_data = base64.b64encode(f.read()).decode('utf-8')

payload = {
    'model': 'google/gemini-2.0-flash-001',
    'messages': [
        {
            'role': 'user',
            'content': [
                {
                    'type': 'image_url',
                    'image_url': {'url': f'data:image/png;base64,{img_data}'}
                },
                {
                    'type': 'text',
                    'text': '''Analyze this social media poster carefully. Describe:
1. The overall composition and layout (dimensions seem to be 2746x1371 - landscape)
2. Where is the main subject/focal point? Give approximate position as percentage from left (0-100%) and from top (0-100%)
3. Where are important text elements and logos? Give positions as percentages.
4. What is in the background vs foreground?
5. Is the important content more to the left, center, or right? More to the top, middle, or bottom?
6. What are the key visual elements that absolutely must NOT be cropped out?
7. If we need to crop to square (1:1), portrait 4:5, and portrait 9:16 - what center point should we focus on?

Be very specific with percentage positions. This is critical for automated cropping.'''
                }
            ]
        }
    ]
}

data = json.dumps(payload).encode('utf-8')
req = urllib.request.Request(
    f\"{os.environ['OPENROUTER_BASE_URL']}/chat/completions\",
    data=data,
    headers={
        'Content-Type': 'application/json',
        'Authorization': f\"Bearer {os.environ['OPENROUTER_API_KEY']}\"
    }
)

with urllib.request.urlopen(req, timeout=60) as resp:
    result = json.loads(resp.read().decode('utf-8'))
    print(result['choices'][0]['message']['content'])
"

