    img_data = base64.b64encode(f.read()).decode('utf-8')

payload = {
    'model': 'google/gemini-3.5-flash',
    'messages': [
        {
            'role': 'user',
            'content': [
                {
                    'type': 'image_url',
                    'image_url': {'url': f'data:image/png;base64,{img_data}'}
                },
                {
                    'type': 'text',
                    'text': '''Analyze this social media poster (2746x1371 pixels, landscape orientation). I need to crop it for:
